sql:
SELECT respondent_id, age
FROM respondents
WHERE gender = 'Female' AND age BETWEEN 18 AND 65;

SELECT COUNT(*)
FROM respondents
WHERE wage_per_hour > (SELECT AVG(wage_per_hour) FROM respondents);

